#!/usr/bin/env bun

//<skill-gen>
// ---
// name: workflow-gen
// description: "Use when adding, modifying, generating, checking, or debugging repo-local GitHub Actions workflow fragments embedded in source code with //<workflow-gen> markers."
// ---
//
// # workflow-gen
//
// Scans source files for `//<workflow-gen>` markers, extracts YAML workflow fragments, merges them by workflow name, and writes `.github/workflows/<name>.yml` plus `required-workflows.json`.
//
// **Full specification:** `packages/ci/workflow-gen/SPEC.md`
//
// ## Quick Reference
//
// ### Fragment Format
//
// Embed workflow fragments in any source file using comment markers:
//
// ```ts
// //<workflow-gen>
// // name: my-workflow
// // required: true
// // on:
// //   push:
// //     branches: [main]
// //   pull_request: {}
// // jobs:
// //   build:
// //     name: Build
// //     steps:
// //       - uses: actions/checkout@v5
// //       - uses: ./.github/actions/setup
// //       - name: Build
// //         run: bun run build
// //</workflow-gen>
// ```
//
// - **`name`** (required): output filename stem and merge key.
// - **`required: true`**: writes job display names to `required-workflows.json` for branch protection.
// - Comment prefixes (`//` or `#`) are stripped automatically.
//
// ### Template Variables
//
// | Variable | Expands to |
// |----------|------------|
// | `\$$file` | Relative path from repo root to the source file |
// | `\$$directory` | Relative path from repo root to the source file's directory |
//
// ### CLI Commands
//
// ```bash
// bun run workflow-gen:generate
// bun run workflow-gen:check
// bun run workflow-gen:e2e-test
// ```
//
// ### Merge Rules
//
// | Key | Strategy |
// |-----|----------|
// | `on` | Union of trigger definitions |
// | `env`, `permissions` | Shallow merge, later wins |
// | `concurrency` | Last writer wins |
// | `jobs` | Merge by job id; repeated `steps` arrays are concatenated |
//
// ### Key Behaviors
//
// - Jobs without `runs-on` and without `uses:` get `runs-on: ubuntu-latest`.
// - Hand-written workflow files (without `AUTO-GENERATED by workflow-gen`) are never overwritten.
// - `check` detects missing, changed, and stale generated workflows.
// - Workflows marked `required: true` must have an unfiltered `pull_request` or `pull_request_target` trigger.
//</skill-gen>

//<workflow-gen>
// name: check-generated
// required: true
// on:
//   push:
//     branches: [main]
//   pull_request: {}
//   workflow_dispatch: {}
// permissions:
//   contents: read
// concurrency:
//   group: check-generated-${{ github.ref }}
//   cancel-in-progress: true
// jobs:
//   check-generated:
//     name: Check generated artifacts are up-to-date
//     timeout-minutes: 10
//     steps:
//       - uses: actions/checkout@v5
//       - uses: ./.github/actions/setup
//       - name: Check generated skills
//         run: bun run skill-gen:check
//       - name: Check generated workflows
//         run: bun run workflow-gen:check
//</workflow-gen>

//<workflow-gen>
// name: e2e-test-workflow-gen
// on:
//   push:
//     branches: [main]
//     paths: ["$$directory/**", "package.json", "bun.lock"]
//   pull_request:
//     paths: ["$$directory/**", "package.json", "bun.lock"]
//   workflow_dispatch: {}
// permissions:
//   contents: read
// concurrency:
//   group: e2e-test-workflow-gen-${{ github.ref }}
//   cancel-in-progress: true
// jobs:
//   e2e-test-workflow-gen:
//     name: E2E test workflow-gen
//     timeout-minutes: 10
//     steps:
//       - uses: actions/checkout@v5
//       - uses: ./.github/actions/setup
//       - name: Run e2e test
//         run: bun run workflow-gen:e2e-test
//</workflow-gen>

/**
 * workflow-gen
 *
 * Scans source files for workflow-gen markers, extracts YAML workflow
 * fragments, merges them by workflow name, and writes GitHub Actions
 * workflow files.
 */

import { execSync } from 'node:child_process';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, resolve } from 'node:path';
import { BunRuntime, BunServices } from '@effect/platform-bun';
import { Console, Effect, Option } from 'effect';
import { Command, Flag } from 'effect/unstable/cli';
import { collectWorkflowFiles, compareFile } from './e2e';
import { mergeFragments } from './merge';
import {
  checkRequiredWorkflows,
  checkWorkflows,
  collectRequired,
  formatDiffs,
  validateRequired,
  writeRequiredWorkflows,
  writeWorkflows,
} from './output';
import { parseFragment } from './parse';
import { scan } from './scan';

/** Detect git repo root, falling back to cwd. */
function detectRepoRoot(): string {
  try {
    return execSync('git rev-parse --show-toplevel', {
      encoding: 'utf-8',
    }).trim();
  } catch {
    return process.cwd();
  }
}

/** Produce merged workflows for a base directory, skipping the output directory. */
async function runPipeline(
  baseDir: string,
  outputDir: string,
  verbose: boolean
) {
  const rawFragments = await scan(baseDir, outputDir, verbose);

  if (verbose) {
    // biome-ignore lint/suspicious/noConsole: CLI diagnostic output
    console.log(`pipeline: found ${rawFragments.length} raw fragment(s)`);
  }

  const parsed = rawFragments
    .map(parseFragment)
    .filter(
      (fragment): fragment is NonNullable<typeof fragment> => fragment !== null
    );
  const merged = mergeFragments(parsed, verbose);
  validateRequired(merged);

  if (verbose) {
    // biome-ignore lint/suspicious/noConsole: CLI diagnostic output
    console.log(`pipeline: merged into ${merged.size} workflow(s)`);
  }

  return merged;
}

/** Resolve default output directory for a base repo path. */
function defaultOutputDir(baseDir: string): string {
  return resolve(baseDir, '.github', 'workflows');
}

const baseOption = Flag.string('base').pipe(
  Flag.withDescription('Base folder to scan (default: repo root)'),
  Flag.optional
);

const outputOption = Flag.string('output').pipe(
  Flag.withDescription(
    'Output folder for generated workflows (default: <base>/.github/workflows)'
  ),
  Flag.optional
);

const verboseOption = Flag.boolean('verbose').pipe(
  Flag.withDescription('Print discovered fragments and merge diagnostics'),
  Flag.withDefault(false)
);

const generate = Command.make(
  'generate',
  { base: baseOption, output: outputOption, verbose: verboseOption },
  ({ base, output, verbose }) =>
    Effect.gen(function* () {
      const baseDir = Option.getOrElse(base, detectRepoRoot);
      const outputDir = Option.getOrElse(output, () =>
        defaultOutputDir(baseDir)
      );

      const merged = yield* Effect.promise(() =>
        runPipeline(baseDir, outputDir, verbose)
      );
      const requiredChecks = collectRequired(merged);
      yield* Effect.promise(() => writeWorkflows(merged, outputDir, verbose));
      yield* Effect.promise(() =>
        writeRequiredWorkflows(requiredChecks, baseDir, verbose)
      );

      yield* Console.log(
        `generate: wrote ${merged.size} workflow(s) to ${outputDir}`
      );
    })
).pipe(
  Command.withDescription(
    'Scan, merge, and write GitHub Actions workflow files'
  )
);

const check = Command.make(
  'check',
  { base: baseOption, output: outputOption, verbose: verboseOption },
  ({ base, output, verbose }) =>
    Effect.gen(function* () {
      const baseDir = Option.getOrElse(base, detectRepoRoot);
      const outputDir = Option.getOrElse(output, () =>
        defaultOutputDir(baseDir)
      );

      const merged = yield* Effect.promise(() =>
        runPipeline(baseDir, outputDir, verbose)
      );
      const requiredChecks = collectRequired(merged);
      const workflowDiffs = yield* Effect.promise(() =>
        checkWorkflows(merged, outputDir)
      );
      const requiredDiff = yield* Effect.promise(() =>
        checkRequiredWorkflows(requiredChecks, baseDir)
      );
      const diffs =
        requiredDiff === undefined
          ? workflowDiffs
          : [...workflowDiffs, requiredDiff];

      if (diffs.length === 0) {
        yield* Console.log('check: all workflows are up-to-date');
        return;
      }

      yield* Console.error(`check: ${diffs.length} difference(s) found`);
      yield* Console.error(formatDiffs(diffs));
      return yield* Effect.fail(1);
    })
).pipe(Command.withDescription('Dry-run: exit 1 if generated output differs'));

const e2eTest = Command.make(
  'e2e-test',
  { verbose: verboseOption },
  ({ verbose }) =>
    Effect.gen(function* () {
      const projectDir = resolve(
        dirname(new URL(import.meta.url).pathname),
        '..'
      );
      const testDir = resolve(projectDir, 'e2e-test');
      const expectedDir = resolve(projectDir, 'e2e-test-expected');
      const tmpOutput = mkdtempSync(resolve(tmpdir(), 'workflow-gen-e2e-'));

      try {
        const merged = yield* Effect.promise(() =>
          runPipeline(testDir, tmpOutput, verbose)
        );
        yield* Effect.promise(() => writeWorkflows(merged, tmpOutput, verbose));

        const expectedFiles = yield* Effect.promise(() =>
          collectWorkflowFiles(expectedDir)
        );

        const results = yield* Effect.promise(() =>
          Promise.all(
            expectedFiles.map((file) =>
              compareFile(file, expectedDir, tmpOutput)
            )
          )
        );

        let hasError = results.some((ok) => !ok);

        const actualFiles = yield* Effect.promise(() =>
          collectWorkflowFiles(tmpOutput)
        );
        for (const file of actualFiles) {
          if (!expectedFiles.includes(file)) {
            yield* Console.error(`FAIL: unexpected file ${file} in output`);
            hasError = true;
          }
        }

        if (hasError) {
          yield* Console.error('e2e-test: FAILED');
          return yield* Effect.fail(1);
        }

        yield* Console.log('e2e-test: PASSED');
      } finally {
        rmSync(tmpOutput, { recursive: true, force: true });
      }
    })
).pipe(Command.withDescription('Run e2e tests against fixtures'));

const root = Command.make('workflow-gen').pipe(
  Command.withSubcommands([generate, check, e2eTest]),
  Command.withDescription(
    'Generate GitHub Actions workflows from //<workflow-gen> source markers'
  )
);

Command.run(root, { version: '0.0.1' }).pipe(
  Effect.catch((error) =>
    Effect.sync(() => process.exit(typeof error === 'number' ? error : 1))
  ),
  Effect.provide(BunServices.layer),
  BunRuntime.runMain
);
